/*
 * test_deflate.c - Unit tests for DEFLATE decompressor
 *
 * Tests the deflate decompressor with various block types and edge cases.
 * Uses real compressed data generated by Python zlib.
 */

#include <stdio.h>
#include <string.h>
#include <windows.h>
#include "../src/utils/deflate.h"
#include "test_data.h"

/* Test result tracking */
static int tests_passed = 0;
static int tests_failed = 0;

/* Test helper macro */
#define TEST_ASSERT(condition, message) \
    do { \
        if (condition) { \
            printf("  PASS: %s\n", message); \
            tests_passed++; \
        } else { \
            printf("  FAIL: %s\n", message); \
            tests_failed++; \
        } \
    } while (0)

/* Test 1: Uncompressed block (BTYPE=00) */
static void test_uncompressed_block(void)
{
    printf("\nTest 1: Uncompressed block\n");

    BYTE input[] = {
        0x01,       /* BFINAL=1, BTYPE=00 */
        0x05, 0x00, /* LEN = 5 */
        0xFA, 0xFF, /* NLEN = ~5 */
        'H', 'e', 'l', 'l', 'o'
    };

    BYTE output[32] = {0};
    DEFLATE_CTX ctx;

    deflate_init(&ctx, input, sizeof(input), output, sizeof(output));
    int ret = deflate_decompress(&ctx);

    TEST_ASSERT(ret == DEFLATE_OK, "Decompression returns OK");
    TEST_ASSERT(ctx.out_pos == 5, "Output length is 5");
    TEST_ASSERT(memcmp(output, "Hello", 5) == 0, "Output data matches 'Hello'");
}

/* Test 2: Real compressed data - Hello World */
static void test_real_hello(void)
{
    printf("\nTest 2: Real compressed data - Hello World\n");

    BYTE output[256] = {0};
    DEFLATE_CTX ctx;

    deflate_init(&ctx, test_hello_compressed, sizeof(test_hello_compressed),
                 output, sizeof(output));
    int ret = deflate_decompress(&ctx);

    TEST_ASSERT(ret == DEFLATE_OK, "Decompression returns OK");
    TEST_ASSERT(ctx.out_pos == sizeof(test_hello_original), "Output length matches original");
    TEST_ASSERT(memcmp(output, test_hello_original, sizeof(test_hello_original)) == 0,
                "Output data matches original");
}

