/* Test 5: Real compressed data - Zeros (RLE) */
static void test_real_zeros(void)
{
    printf("\nTest 5: Real compressed data - Zeros (RLE)\n");

    BYTE output[2048] = {0};
    DEFLATE_CTX ctx;

    printf("  Original size: %zu\n", sizeof(test_zeros_original));
    printf("  Compressed size: %zu\n", sizeof(test_zeros_compressed));
    printf("  Compressed data: ");
    for (size_t i = 0; i < sizeof(test_zeros_compressed); i++) {
        printf("%02X ", test_zeros_compressed[i]);
    }
    printf("\n");

    deflate_init(&ctx, test_zeros_compressed, sizeof(test_zeros_compressed),
                 output, sizeof(output));
    int ret = deflate_decompress(&ctx);

    printf("  Return code: %d\n", ret);
    printf("  Output size: %zu\n", ctx.out_pos);

    TEST_ASSERT(ret == DEFLATE_OK, "Decompression returns OK");
    TEST_ASSERT(ctx.out_pos == sizeof(test_zeros_original), "Output length matches original");
    TEST_ASSERT(memcmp(output, test_zeros_original, sizeof(test_zeros_original)) == 0,
                "Output data matches original");
}

