/* Test 9: Empty input */
static void test_empty_input(void)
{
    printf("\nTest 9: Empty input\n");

    BYTE output[32] = {0};
    DEFLATE_CTX ctx;

    deflate_init(&ctx, NULL, 0, output, sizeof(output));
    int ret = deflate_decompress(&ctx);

    TEST_ASSERT(ret == DEFLATE_BAD_INPUT, "Empty input returns BAD_INPUT");
}

/* Test 10: Invalid block type (BTYPE=11) */
static void test_invalid_block_type(void)
{
    printf("\nTest 10: Invalid block type\n");

    BYTE input[] = { 0x07 };  /* BFINAL=1, BTYPE=11 */
    BYTE output[32] = {0};
    DEFLATE_CTX ctx;

    deflate_init(&ctx, input, sizeof(input), output, sizeof(output));
    int ret = deflate_decompress(&ctx);

    TEST_ASSERT(ret == DEFLATE_BAD_INPUT, "Invalid block type returns BAD_INPUT");
}

/* Test 11: Output buffer too small */
static void test_output_too_small(void)
{
    printf("\nTest 11: Output buffer too small\n");

    BYTE output[3] = {0};  /* Too small for 5 bytes */
    DEFLATE_CTX ctx;

    deflate_init(&ctx, test_hello_compressed, sizeof(test_hello_compressed),
                 output, sizeof(output));
    int ret = deflate_decompress(&ctx);

    TEST_ASSERT(ret == DEFLATE_ERROR, "Small buffer returns ERROR");
}

/* Test 12: Multiple uncompressed blocks */
static void test_multiple_blocks(void)
{
    printf("\nTest 12: Multiple uncompressed blocks\n");

    BYTE input[] = {
        0x00,       /* BFINAL=0, BTYPE=00 */
        0x03, 0x00, /* LEN = 3 */
        0xFC, 0xFF, /* NLEN = ~3 */
        'H', 'e', 'l',
        0x01,       /* BFINAL=1, BTYPE=00 */
        0x02, 0x00, /* LEN = 2 */
        0xFD, 0xFF, /* NLEN = ~2 */
        'l', 'o'
    };

    BYTE output[32] = {0};
    DEFLATE_CTX ctx;

    deflate_init(&ctx, input, sizeof(input), output, sizeof(output));
    int ret = deflate_decompress(&ctx);

    TEST_ASSERT(ret == DEFLATE_OK, "Multiple blocks returns OK");
    TEST_ASSERT(ctx.out_pos == 5, "Output length is 5");
    TEST_ASSERT(memcmp(output, "Hello", 5) == 0, "Output data matches 'Hello'");
}

/* Main test runner */
int main(void)
{
    printf("=== DEFLATE Decompressor Unit Tests ===\n");
    printf("Using real compressed data from Python zlib\n");

    test_uncompressed_block();
    test_real_hello();
    test_real_repeat();
    test_real_binary();
    test_real_zeros();
    test_real_pseudo_random();
    test_real_single_byte();
    test_real_all_bytes();
    test_empty_input();
    test_invalid_block_type();
    test_output_too_small();
    test_multiple_blocks();

    printf("\n=== Test Results ===\n");
    printf("Passed: %d\n", tests_passed);
    printf("Failed: %d\n", tests_failed);
    printf("Total:  %d\n", tests_passed + tests_failed);

    return tests_failed > 0 ? 1 : 0;
}
